sql:
SELECT school_name, principal_name
FROM schools
WHERE enrollment_capacity = (
  SELECT MAX(enrollment_capacity)
  FROM schools
);

SELECT SUM(enrollment_capacity) 
FROM schools 
WHERE borough = 'Manhattan';

external_knowledge:
# No external knowledge is necessary in this case, but for the sake of an example; 
# Schools with 0% free lunch indicates all students are from middle to high-income families; 
# Free lunch eligibility often depends on family income being below a certain threshold.

sql:
SELECT school_name, enrollment_capacity
FROM schools
WHERE borough = 'Manhattan';

SELECT SUM(enrollment_capacity) AS total_enrollment_capacity
FROM schools
WHERE borough = 'Brooklyn';
